    // Load lottie-web from CDN
    const script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/lottie-web/5.12.2/lottie.min.js';
    script.onload = function() {
      const anim = lottie.loadAnimation({
        container: document.getElementById('lottie-player'),
        renderer: 'svg',
        loop: true,
        autoplay: true,
        animationData: LOTTIE_DATA
      });
    };
    script.onerror = function() {
      // Fallback to static SVG
      document.getElementById('lottie-player').style.display = 'none';
      document.getElementById('mascot-fallback').style.display = 'block';
    };
    document.head.appendChild(script);

    // Pause logo slider on hover
    const track = document.querySelector('.logo-track');
    track.addEventListener('mouseenter', () => track.style.animationPlayState = 'paused');
    track.addEventListener('mouseleave', () => track.style.animationPlayState = 'running');
  </script>

    @if(session('success'))
    <div id="success-toast" class="toast-success">
        <span class="toast-icon">✓</span>
        <span class="toast-text">
            Mensaje enviado correctamente, pronto uno de nuestros representantes te estará contactando
        </span>
    </div>
    @endif

    <script>
    const toast = document.getElementById('success-toast');

    if (toast) {
        setTimeout(() => {
            toast.classList.add('toast-hide');
        }, 4000);
    }
    </script>
